export function renderTable(logger, rows) {
    logger.log("");
    const availableColumns = process.stdout.columns || 80;
    const hasScores = rows.some((row) => row.score !== null);
    const columns = rows[0]?.columns;
    if (!columns) {
        return;
    }
    const numColumns = columns.length + (hasScores ? 1 : 0);
    // Calculate table overhead: borders (numColumns + 1) + padding (numColumns × 2)
    const tableOverhead = numColumns * 3 + 1;
    const scoreWidth = hasScores ? 5 : 0;
    const availableInnerSpace = availableColumns - tableOverhead - scoreWidth;
    const colWidth = Math.min(Math.floor(availableInnerSpace / columns.length), 80);
    logger.log(table([
        [
            ...columns.map((col) => c.cyan(c.bold(col.label))),
            ...(hasScores ? [c.cyan(c.bold("Score"))] : []),
        ],
        ...rows.map((row) => [
            ...row.columns.map((col) => {
                return typeof col.value === "object"
                    ? inspect(col.value, {
                        colors: true,
                        depth: null,
                        breakLength: colWidth,
                        numericSeparator: true,
                        compact: true,
                    })
                    : col.value;
            }),
            ...(hasScores ? [displayScore(row.score)] : []),
        ]),
    ], {
        columns: [
            ...columns.map((col) => ({
                width: colWidth,
                wrapWord: typeof col.value === "string",
                truncate: 200,
                paddingLeft: 1,
                paddingRight: 1,
            })),
            ...(hasScores ? [{ width: scoreWidth }] : []),
        ],
    }));
}
export function renderScoreDisplay(logger, failedTasksCount, averageScore) {
    const scoreDisplay = failedTasksCount > 0
        ? c.red("✖ ") + c.dim(`(${failedTasksCount} failed)`)
        : displayScore(averageScore);
    logger.log(["      ", c.dim("Score"), "  ", scoreDisplay].join(""));
}
export function renderThreshold(logger, scoreThreshold, averageScore) {
    let thresholdScoreSuffix = "";
    let result;
    if (averageScore === null || averageScore * 100 < scoreThreshold) {
        thresholdScoreSuffix = `${c.dim(` (failed)`)}`;
        result = "failed";
    }
    else {
        thresholdScoreSuffix = `${c.dim(` (passed)`)}`;
        result = "passed";
    }
    logger.log([
        "  ",
        c.dim("Threshold"),
        "  ",
        c.bold(scoreThreshold + "%"),
        thresholdScoreSuffix,
    ].join(""));
    return result;
}
export function renderSummaryStats(logger, data) {
    logger.log([" ", c.dim("Eval Files"), "  ", data.totalFiles].join(""));
    logger.log(["      ", c.dim("Evals"), "  ", data.totalEvals].join(""));
    logger.log(["   ", c.dim("Duration"), "  ", `${Math.round(data.maxDuration)}ms`].join(""));
}
export function renderDetailedTable(logger, results, failedCount) {
    renderTable(logger, results.map((result) => ({
        columns: result.renderedColumns.length > 0
            ? result.renderedColumns.map((col) => ({
                label: col.label,
                value: renderMaybeEvaliteFile(col.value),
            }))
            : [
                {
                    label: "Input",
                    value: renderMaybeEvaliteFile(result.input),
                },
                {
                    label: "Output",
                    value: renderMaybeEvaliteFile(result.output),
                },
            ],
        score: result.scores.length === 0
            ? null
            : average(result.scores, (s) => s.score ?? 0),
    })));

