195→function computeWeightedAverage(
196→  intent: GoldenCaseIntent,
197→  scores: Array<{ name: string; score: number | null }>,
198→): number {
199→  const weights = intentScoreWeights[intent];
200→  if (!weights) {
201→    throw new Error(`Unknown golden case intent: ${intent}`);
202→  }
203→
204→  let weightedTotal = 0;
205→  let weightTotal = 0;
206→  for (const [scorerName, weight] of Object.entries(weights)) {
207→    if (weight <= 0) {
208→      continue;
209→    }
210→
211→    weightedTotal += scoreByName(scores, scorerName) * weight;
212→    weightTotal += weight;
213→  }
214→
215→  if (weightTotal === 0) {
216→    throw new Error(`No scorer weights configured for intent: ${intent}`);
