const extractionModel = process.env.EXTRACTION_MODEL ?? "anthropic/claude-3.5-haiku";
const autoevalModel = requireEnv("AUTOEVAL_MODEL");

const cacheDir = process.env.EVAL_CACHE_DIR ?? "eval-results/cache";
const cachePath = join(cacheDir, "extraction-cache.json");
const resultCache = loadCache(cachePath);
const cases = JSON.parse(readFileSync(join(process.cwd(), "evals", "data", "golden-cases.json"), "utf8")) as GoldenCase[];
assertAutoevalEnv();

// strict_single is reserved for unambiguous one-entity probes.
// Cases where multiple extractions are semantically valid should use multi_allowed.
const intentScoreWeights: Record<
  GoldenCaseIntent,
  Record<
    | "entity-precision"
    | "entity-recall"
    | "no-extra-entities"
    | "no-phantom-persons"
    | "evidence-grounded"
    | "no-context-bleed"
    | "evidence-source-current-message"
    | "resolved-from-lineage"
    | "tool-filtering"
    | "forbidden-kinds"
    | "factuality"
    | "relation-recall"
    | "category-accuracy",
    number
  >
> = {
  strict_single: {
    "entity-precision": 0.16,
    "entity-recall": 0.16,
    "no-extra-entities": 0.18,
    "no-phantom-persons": 0.12,
    "evidence-grounded": 0.08,
    "no-context-bleed": 0.05,
    "evidence-source-current-message": 0.05,
    "resolved-from-lineage": 0.04,
    "tool-filtering": 0.06,
    "forbidden-kinds": 0.08,
    factuality: 0.02,
    "relation-recall": 0,
    "category-accuracy": 0.1,
  },
  multi_allowed: {
    "entity-precision": 0.21,
    "entity-recall": 0.21,
    "no-extra-entities": 0.05,
    "no-phantom-persons": 0.11,
    "evidence-grounded": 0.08,
    "no-context-bleed": 0.04,
    "evidence-source-current-message": 0.06,
    "resolved-from-lineage": 0.04,
    "tool-filtering": 0.04,
    "forbidden-kinds": 0.06,
    factuality: 0.02,
    "relation-recall": 0.03,
    "category-accuracy": 0.1,
  },
};

let runtime: EvalRuntime;

beforeAll(async () => {
  runtime = await setupEvalRuntime("extraction");
}, 120_000);

afterAll(async () => {
  await teardownEvalRuntime(runtime);
}, 120_000);

const factualityScorer = createScorer<GoldenCase, ExtractionEvalOutput, GoldenCase>({
  name: "factuality",
  description: "Average factual grounding score for extracted entity texts against matched provenance evidence snippets.",
  scorer: async ({ input, output }) => {
    if (output.extractedEntities.length === 0) {
      return { score: 1 };
    }

    let total = 0;
    for (const entity of output.extractedEntities) {
      const snippet = resolveEntityEvidenceSnippet(entity.text, output.evidenceRows, input.input);
      const result = await Factuality({
        input: snippet,
        output: entity.text,
        expected: snippet,
        model: autoevalModel,
      });
      total += result.score ?? 0;
    }

    return { score: total / output.extractedEntities.length };
  },
});

evalite<GoldenCase, ExtractionEvalOutput, GoldenCase>("Extraction Golden Cases", {
  data: cases.map((testCase) => ({ input: testCase, expected: testCase })),
  task: async (input) => runCase(input),
  scorers: [
    entityPrecisionScorer,
    entityRecallScorer,
    noExtraEntitiesScorer,
    noPhantomPersonsScorer,
    evidenceGroundedScorer,
    noContextBleedScorer,
    evidenceSourceCurrentMessageScorer,
    resolvedFromLineageScorer,
    toolFilteringScorer,
    forbiddenKindsScorer,
    relationRecallScorer,
    categoryAccuracyScorer,
    factualityScorer,
  ],
  columns: ({ input, output, scores }) => [
    { label: "Model", value: extractionModel },
    { label: "Precision", value: formatScoreCell(scoreByName(scores, "entity-precision")) },
    { label: "Recall", value: formatScoreCell(scoreByName(scores, "entity-recall")) },
    { label: "NoExtra", value: formatScoreCell(scoreByName(scores, "no-extra-entities")) },
    { label: "NoPeople", value: formatScoreCell(scoreByName(scores, "no-phantom-persons")) },
    { label: "Evidence", value: formatScoreCell(scoreByName(scores, "evidence-grounded")) },
    { label: "NoCtxBleed", value: formatScoreCell(scoreByName(scores, "no-context-bleed")) },
    { label: "EvSrc", value: formatScoreCell(scoreByName(scores, "evidence-source-current-message")) },
    { label: "Lineage", value: formatScoreCell(scoreByName(scores, "resolved-from-lineage")) },
    { label: "Tools", value: formatScoreCell(scoreByName(scores, "tool-filtering")) },
    { label: "Kinds", value: formatScoreCell(scoreByName(scores, "forbidden-kinds")) },
    { label: "RelRecall", value: formatScoreCell(scoreByName(scores, "relation-recall")) },
    { label: "Category", value: formatScoreCell(scoreByName(scores, "category-accuracy")) },
    { label: "Factual", value: formatScoreCell(scoreByName(scores, "factuality")) },
